    if (isEmpty(s)) {
        fprintf(stderr, "Stack underflow\n");
        exit(1);
    }
    Node *temp = s->top;
    int val = temp->data;
    s->top = temp->next;
    free(temp);
    s->size--;
    return val;
}

int peek(Stack *s) {
    if (isEmpty(s)) {
        fprintf(stderr, "Stack is empty\n");
        exit(1);
    }
    return s->top->data;
}

void freeStack(Stack *s) {
    while (!isEmpty(s))
        pop(s);
}

