char pop(void)       { return stack[top--]; }
char peek(void)      { return stack[top]; }
int isEmpty(void)    { return top == -1; }

int precedence(char op) {
    switch (op) {
        case '+': case '-': return 1;
        case '*': case '/': return 2;
        case '^': return 3;
        default: return 0;
    }
}

int isRightAssociative(char op) {
    return op == '^';
}

void infixToPostfix(const char *infix, char *postfix) {
    int j = 0;

    for (int i = 0; infix[i] != '\0'; i++) {
        char c = infix[i];

        if (isalnum(c)) {
            postfix[j++] = c;  /* operand -> output */
        } else if (c == '(') {
            push(c);
        } else if (c == ')') {
            while (!isEmpty() && peek() != '(')
                postfix[j++] = pop();
            pop();  /* discard '(' */
        } else {  /* operator */
            while (!isEmpty() && peek() != '(' &&
                   (precedence(peek()) > precedence(c) ||
                    (precedence(peek()) == precedence(c) && !isRightAssociative(c)))) {
                postfix[j++] = pop();
            }
            push(c);
        }
    }

    /* Pop remaining operators */
    while (!isEmpty())
        postfix[j++] = pop();

    postfix[j] = '\0';
}

int main(void) {
    char postfix[MAX];

    infixToPostfix("A+B*C", postfix);
    printf("A+B*C -> %s\n", postfix);       /* ABC*+ */

    infixToPostfix("(A+B)*C", postfix);
    printf("(A+B)*C -> %s\n", postfix);     /* AB+C* */

    infixToPostfix("A+B*C-D/E", postfix);
    printf("A+B*C-D/E -> %s\n", postfix);   /* ABC*+DE/- */

    infixToPostfix("A^B^C", postfix);
    printf("A^B^C -> %s\n", postfix);       /* ABC^^ (right-associative) */

    return 0;
}

int precedence(char op) {
    if (op == '+' || op == '-') return 1;
    if (op == '*' || op == '/') return 2;
    return 0;
}

void infixToPostfix(const char *in, char *out) {
    char stack[100]; int top = -1, j = 0;
    for (int i = 0; in[i]; i++) {
        char c = in[i];
        if (isalnum(c)) out[j++] = c;
        else if (c == '(') stack[++top] = c;
        else if (c == ')') {
            while (stack[top] != '(') out[j++] = stack[top--];
            top--;  /* discard '(' */
        } else {
            while (top >= 0 && stack[top] != '(' &&
                   precedence(stack[top]) >= precedence(c))
