int isBalanced(const char *expr) {
    top = -1;  /* reset stack */

    for (int i = 0; expr[i] != '\0'; i++) {
        char c = expr[i];

        if (c == '(' || c == '[' || c == '{') {
            push(c);
        } else if (c == ')' || c == ']' || c == '}') {
            if (isEmpty())
                return 0;  /* extra closing bracket */
            char open = pop();
            if (!isMatchingPair(open, c))
                return 0;  /* mismatched brackets */
        }
        /* non-bracket characters are ignored */
    }

    return isEmpty();  /* true if all brackets matched */
}

int main(void) {
    const char *tests[] = {
        "{[()]}",       /* balanced */
        "{[(])}",       /* mismatched */
        "((())",        /* extra opening */
        "())",          /* extra closing */
        "a*(b+c)-[d/e]", /* balanced with non-bracket chars */
