    TreeNode *n = (TreeNode *)malloc(sizeof(TreeNode));
    n->data = val;
    n->left = n->right = NULL;
    return n;
}

/* Height: number of edges on longest root-to-leaf path */
int height(TreeNode *root) {
    if (root == NULL)
        return -1;  /* edge convention: empty tree has height -1 */

    int leftH = height(root->left);
    int rightH = height(root->right);

    return 1 + (leftH > rightH ? leftH : rightH);
}

/* Alternative: node-count convention (height = number of nodes on longest path) */
int heightNodeCount(TreeNode *root) {
    if (root == NULL)
        return 0;

    int leftH = heightNodeCount(root->left);
    int rightH = heightNodeCount(root->right);

    return 1 + (leftH > rightH ? leftH : rightH);
}

/* Depth of a specific node (distance from root) */
int depth(TreeNode *root, int target, int currentDepth) {
    if (root == NULL) return -1;
    if (root->data == target) return currentDepth;

    int left = depth(root->left, target, currentDepth + 1);
    if (left != -1) return left;
    return depth(root->right, target, currentDepth + 1);
}

